function candidate(path, keepParents) {
  if (path === "") return "";

  const output = [];
  const parts = path.split("/");

  for (const part of parts) {
    if (part === "" || part === ".") continue;

    if (part === "..") {
      const last = output[output.length - 1];
      if (last && last !== "..") {
        output.pop();
      } else if (keepParents) {
        output.push("..");
      }
    } else {
      output.push(part);
    }
  }

  return output.join("/");
}
